def gen(rng, size):
    n = max(1, size)
    colors = ''.join(chr(ord('a') + rng.randint(0, 3)) for _ in range(n))
    edges = []
    for u in range(n):
        for _ in range(rng.randint(0, 2)):
            if u + 1 < n:
                v = rng.randint(u + 1, n - 1)
                edges.append([u, v])
    return [colors, edges]

