class Solution:
    def largestPathValue(self, colors, edges):
        n = len(colors)
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
        # iterative DFS topological sort with cycle detection
        state = [0] * n  # 0 unvisited, 1 in-stack, 2 done
        order = []
        for s in range(n):
            if state[s] != 0:
                continue
            stack = [(s, 0)]
            while stack:
                node, idx = stack[-1]
                if idx == 0:
                    state[node] = 1
                if idx < len(adj[node]):
                    stack[-1] = (node, idx + 1)
                    nxt = adj[node][idx]
                    if state[nxt] == 1:
                        return -1
                    if state[nxt] == 0:
                        stack.append((nxt, 0))
                else:
                    state[node] = 2
                    order.append(node)
                    stack.pop()
        # order is reverse-topological; process so predecessors come first
        order.reverse()
        rev = [[] for _ in range(n)]
        for a, b in edges:
            rev[b].append(a)
        dp = [[0] * 26 for _ in range(n)]
        best = 0
        for node in order:
            c = ord(colors[node]) - 97
            for p in rev[node]:
                for k in range(26):
                    if dp[p][k] > dp[node][k]:
                        dp[node][k] = dp[p][k]
            dp[node][c] += 1
            m = max(dp[node])
            if m > best:
                best = m
        return best

