from collections import deque
class Solution:
    def largestPathValue(self, colors, edges):
        n = len(colors)
        adj = [[] for _ in range(n)]
        indeg = [0] * n
        for a, b in edges:
            adj[a].append(b)
            indeg[b] += 1
        dp = [[0] * 26 for _ in range(n)]
        q = deque(i for i in range(n) if indeg[i] == 0)
        seen = 0
        best = 0
        while q:
            u = q.popleft()
            seen += 1
            c = ord(colors[u]) - 97
            dp[u][c] += 1
            if dp[u][c] > best:
                best = dp[u][c]
            for v in adj[u]:
                for k in range(26):
                    if dp[u][k] > dp[v][k]:
                        dp[v][k] = dp[u][k]
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        return best if seen == n else -1

